def read_box_header(data: bytes, offset: int) -> BoxHeader:
    if offset + 8 > len(data):
        raise HeicBoxError("Truncated ISO-BMFF box header.")
    size = _read_u32_be(data, offset)
    box_type = data[offset + 4 : offset + 8]
    header_size = 8
    if size == 1:
        if offset + 16 > len(data):
            raise HeicBoxError("Truncated extended ISO-BMFF box header.")
        size = _read_u64_be(data, offset + 8)
        header_size = 16
    elif size == 0:
        size = len(data) - offset
    if size < header_size:
        raise HeicBoxError(f"Invalid box size for {box_type!r}.")
    if offset + size > len(data):
        raise HeicBoxError(f"Box {box_type!r} extends past end of file.")
    return BoxHeader(offset=offset, size=size, box_type=box_type, header_size=header_size)

