def parse_ftyp(data: bytes, header: BoxHeader) -> tuple[str, list[str]]:
    payload = data[header.payload_offset : header.end_offset]
    if len(payload) < 8:
        raise HeicBoxError("ftyp box is too short.")
    major = payload[0:4].decode("ascii", errors="replace")
    brands = [major]
    for index in range(8, len(payload), 4):
        brands.append(payload[index : index + 4].decode("ascii", errors="replace"))
    return major, brands

