def parse_ispe(data: bytes, header: BoxHeader) -> tuple[int, int]:
    payload = data[header.payload_offset : header.end_offset]
    if len(payload) < 12:
        raise HeicBoxError("ispe box is too short.")
    width = _read_u32_be(payload, 4)
    height = _read_u32_be(payload, 8)
    if width <= 0 or height <= 0:
        raise HeicBoxError("ispe dimensions are invalid.")
    return width, height

