def is_heic_container(data: bytes) -> bool:
    if len(data) < 12:
        return False
    try:
        header = read_box_header(data, 0)
    except HeicBoxError:
        return False
    if header.box_type != b"ftyp":
        return False
    try:
        major, brands = parse_ftyp(data, header)
    except HeicBoxError:
        return False
    normalized = {major.encode("ascii", errors="ignore"), *(
        brand.encode("ascii", errors="ignore") for brand in brands
    )}
    return bool(normalized & HEIC_MAJOR_BRANDS)

