def _collect_box_types(data: bytes, start: int, end: int, limit: int = 48) -> list[str]:
    names: list[str] = []
    for header in iter_boxes(data, start, end):
        name = header.box_type.decode("ascii", errors="replace")
        if name and name not in names:
            names.append(name)
        if len(names) >= limit:
            break
        if header.box_type in {b"meta", b"iprp", b"ipco", b"iloc", b"mdat"}:
            child_end = header.end_offset
            if header.box_type == b"meta" and header.end_offset - header.payload_offset >= 4:
                child_start = header.payload_offset + 4
            else:
                child_start = header.payload_offset
            if child_start < child_end:
                for child_name in _collect_box_types(data, child_start, child_end, limit - len(names)):
                    if child_name not in names:
                        names.append(child_name)
                    if len(names) >= limit:
                        break
    return names

